  async batchSetFlags(
    userId: string,
    config: IAccountConfig,
    operations: BatchFlagOperation[],
  ): Promise<{ success: number; failed: number }> {
    let success = 0;
    let failed = 0;

    for (const op of operations) {
      for (const uid of op.uids) {
        try {
          await this.setFlags(
            userId,
            config,
            op.mailbox,
            uid,
            op.flags,
            op.action,
          );
          success++;
