  private normalizeFlags(raw: string[]): NormalizedFlags {
    const parsed: NormalizedFlags = {
      seen: false,
      answered: false,
      flagged: false,
      deleted: false,
      draft: false,
      recent: false,
      custom: [],
    };

    for (const flag of raw) {
      switch (flag) {
        case '\\Seen':
          parsed.seen = true;
          break;
        case '\\Answered':
          parsed.answered = true;
          break;
        case '\\Flagged':
          parsed.flagged = true;
          break;
        case '\\Deleted':
          parsed.deleted = true;
          break;
        case '\\Draft':
          parsed.draft = true;
          break;
        case '\\Recent':
          parsed.recent = true;
          break;
        default:
          if (!flag.startsWith('\\')) {
            parsed.custom.push(flag);
          }
      }
    }

    return parsed;
  }

  private getNestedMap<K1, K2, K3, V>(
    map: Map<K1, Map<K2, Map<K3, V>>>,
    keys: [K1, K2, K3],
  ): V | undefined {
    const l1 = map.get(keys[0]);
    if (!l1) return undefined;
    const l2 = l1.get(keys[1]);
    if (!l2) return undefined;
    return l2.get(keys[2]);
  }

  destroy(): void {
    this.recentEvents.clear();
    this.flagCache.clear();
    this.removeAllListeners();
  }
}

